from beeai import Agent
from beeai.events import MemoryEvent

class MemoryGrowthDetector:
    def __init__(self):
        self.baseline_memory = {}
        self.growth_threshold = 2.0  # 2x growth triggers alert

    def on_memory_event(self, event: MemoryEvent):
        agent_id = event.agent_id
        current_memory = event.memory_usage_mb

        if agent_id not in self.baseline_memory:
            self.baseline_memory[agent_id] = current_memory
            return

        growth_ratio = current_memory / self.baseline_memory[agent_id]
        session_duration = event.timestamp - event.session_start

        if growth_ratio > self.growth_threshold and session_duration > 3600:
            print(f'🚨 MEMORY LEAK: Agent {agent_id} memory grew {growth_ratio:.1f}x')

from beeai.events import GenerationEvent

class TokenWasteDetector:
    def __init__(self):
        self.retry_threshold = 3
        self.token_waste = {}

    def on_generation_event(self, event: GenerationEvent):
        agent_id = event.agent_id
        retry_count = event.retry_count
        tokens_used = event.input_tokens + event.output_tokens

        if agent_id not in self.token_waste:
            self.token_waste[agent_id] = {'retries': 0, 'total_tokens': 0}

        self.token_waste[agent_id]['retries'] += retry_count
        self.token_waste[agent_id]['total_tokens'] += tokens_used

        if self.token_waste[agent_id]['retries'] > self.retry_threshold:
            waste_pct = (self.token_waste[agent_id]['retries'] * tokens_used) / self.token_waste[agent_id]['total_tokens']
            print(f'🚨 TOKEN WASTE: Agent {agent_id} wasting {waste_pct:.1%} tokens on retries')

