from beeai.tools import Tool
from functools import lru_cache
import hashlib

class CachedTool(Tool):
    def __init__(self, original_tool):
        self.original_tool = original_tool
        self.cache = {}

    @lru_cache(maxsize=1000)
    def _cached_execute(self, args_hash, **kwargs):
        return self.original_tool.execute(**kwargs)

    def execute(self, **kwargs):
        args_str = str(sorted(kwargs.items()))
        args_hash = hashlib.md5(args_str.encode()).hexdigest()

        if args_hash in self.cache:
            print(f'📦 CACHE HIT: {self.original_tool.name}')
            return self.cache[args_hash]

        result = self._cached_execute(args_hash, **kwargs)
        self.cache[args_hash] = result
        return result

from beeai.models import GraniteModel

class CostOptimizedGranite(GraniteModel):
    def parse_output(self, raw_output):
        # Force consistent JSON format
        normalized = {
            'tool_calls': raw_output.get('tool_calls', []),
            'content': raw_output.get('content', ''),
            'finish_reason': raw_output.get('finish_reason', 'stop'),
            'usage': raw_output.get('usage', {'prompt_tokens': 0, 'completion_tokens': 0})
        }

        # Validate required fields
        if not normalized['content']:
            normalized['content'] = ' '

        print(f'✅ Normalized Granite output, saved {len(str(raw_output)) - len(str(normalized))} bytes')
        return normalized
